index b6a80fef4217..9546063e1d78 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -3895,12 +3895,85 @@ static bool isKnownNonEqualFromContext(const Value *V1, const Value *V2,
             .value_or(false) &&
         isValidAssumeForContext(I, Q.CxtI, Q.DT))
       return true;
+      if (isImpliedCondition(I->getArgOperand(0), ICmpInst::ICMP_NE, V1, V2, Q.DL,
+                             /*LHSIsTrue=*/true, Depth)
+              .value_or(false) &&
+          isValidAssumeForContext(I, Q.CxtI, Q.DT))
+        return true;
+  }
+
+  // If ptrtoint(V1) - ptrtoint(V2) is known non-zero, then V1 != V2.
+  // This handles cases like: assume (ptrtoint V1 - ptrtoint V2) == C
+  // where C is known to be non-zero.
+  if (V1->getType()->isPointerTy() && V2->getType()->isPointerTy()) {
+    for (auto &AssumeVH : Q.AC->assumptions()) {
+      if (!AssumeVH)
+        continue;
+      CallInst *I = cast<CallInst>(AssumeVH);
+      if (!isValidAssumeForContext(I, Q.CxtI, Q.DT))
+        continue;
+
+      Value *AssumeArg = I->getArgOperand(0);
+      CmpPredicate Pred;
+      Value *LHS, *RHS;
+
+      // Match icmp Pred LHS, RHS in the assumption.
+      if (!match(AssumeArg, m_c_ICmp(Pred, m_Value(LHS), m_Value(RHS))))
+        continue;
+
+      // We need an equality predicate (EQ or NE).
+      ICmpInst::Predicate IPred = Pred;
+      if (IPred != ICmpInst::ICMP_EQ && IPred != ICmpInst::ICMP_NE)
+        continue;
+
+      // Check if LHS is a subtraction of ptrtoint(V1) and ptrtoint(V2).
+      // Also handle the case where the ptrtoint is truncated.
+      auto isPtrDiff = [&](Value *V, const Value *P1, const Value *P2) -> bool {
+        Value *Op0, *Op1;
+        if (!match(V, m_Sub(m_Value(Op0), m_Value(Op1))))
+          return false;
+        
+        // Check if Op0 is ptrtoint(P1) or trunc(ptrtoint(P1)).
+        Value *Ptr0, *Ptr1;
+        if (match(Op0, m_PtrToInt(m_Value(Ptr0)))) {
+          // Op0 is ptrtoint(Ptr0)
+        } else if (match(Op0, m_Trunc(m_PtrToInt(m_Value(Ptr0))))) {
+          // Op0 is trunc(ptrtoint(Ptr0))
+        } else {
+          return false;
+        }
+        
+        // Check if Op1 is ptrtoint(P2) or trunc(ptrtoint(P2)).
+        if (match(Op1, m_PtrToInt(m_Value(Ptr1)))) {
+          // Op1 is ptrtoint(Ptr1)
+        } else if (match(Op1, m_Trunc(m_PtrToInt(m_Value(Ptr1))))) {
+          // Op1 is trunc(ptrtoint(Ptr1))
+        } else {
+          return false;
+        }
+        
+        return Ptr0 == P1 && Ptr1 == P2;
+      };
+
+      // Check if LHS is (ptrtoint V1 - ptrtoint V2) or (ptrtoint V2 - ptrtoint V1).
+      bool IsPtrDiffV1V2 = isPtrDiff(LHS, V1, V2);
+      bool IsPtrDiffV2V1 = isPtrDiff(LHS, V2, V1);
+
+      if (!IsPtrDiffV1V2 && !IsPtrDiffV2V1)
+        continue;
+
+      // If the predicate is EQ and RHS is known non-zero, then V1 != V2.
+      if (IPred == ICmpInst::ICMP_EQ && isKnownNonZero(RHS, Q))
+        return true;
+
+      // If the predicate is NE and RHS is zero, then V1 != V2.
+      if (IPred == ICmpInst::ICMP_NE && match(RHS, m_Zero()))
+        return true;
+    }
   }

   return false;
 }
