   682 | static void computeKnownBitsFromCmp(const Value *V, CmpInst::Predicate Pred,
   683 |                                     Value *LHS, Value *RHS, KnownBits &Known,
   684 |                                     const SimplifyQuery &Q) {
   685 |   if (RHS->getType()->isPointerTy()) {
